const lines = FILE_CONTENT.split('\n');
const summary = {
  file: 'authorizer.ts',
  totalLines: lines.length,
  imports: lines.filter(l => l.includes('import')).slice(0, 20),
  exports: lines.filter(l => l.includes('export')),
  functions: lines
    .map((line, idx) => ({ line, idx }))
    .filter(({ line }) => line.includes('export ') && line.includes('('))
    .slice(0, 10),
