const lines = FILE_CONTENT.split('\n');
console.log('Total lines:', lines.length);

console.log('\nFunctions that query the graph:');
lines
  .map((line, idx) => ({ line: line.trim(), idx }))
  .filter(({ line }) => line.includes('export') && line.includes('async'))
  .forEach(l => console.log(`  Line ${l.idx}: ${l.line.substring(0, 100)}`));

console.log('\nAll SELECT/LET statements (graph queries):');
lines
  .map((line, idx) => ({ line: line.trim(), idx }))
  .filter(({ line }) => line.includes('SELECT') || line.includes('LET'))
  .forEach(l => console.log(`  Line ${l.idx}: ${l.line.substring(0, 120)}`));

console.log('\nRelationship edges mentioned (-> or <-):');
lines
  .map((line, idx) => ({ line: line.trim(), idx }))
  .filter(({ line }) => line.includes('->') || line.includes('<-') || line.includes('RELATE'))
  .slice(0, 30)
  .forEach(l => console.log(`  Line ${l.idx}: ${l.line.substring(0, 120)}`));

