726→// --- Agent attention sessions ---
727→
728→export type AgentAttentionSessionRow = {
729→  id: RecordId<"agent_session", string>;
730→  orchestrator_status: "idle" | "error";
731→  task_id?: RecordId<"task", string>;
732→  task_title?: string;
733→  error_message?: string;
734→  started_at: string | Date;
735→};
736→
737→export async function listAgentAttentionSessions(
738→  input: WorkspaceQueryInput,
739→): Promise<AgentAttentionSessionRow[]> {
740→  const [rows] = await input.surreal
741→    .query<[
742→      Array<{
743→        id: RecordId<"agent_session", string>;
744→        orchestrator_status: string;
745→        task_id?: RecordId<"task", string>;
746→        error_message?: string;
747→        started_at: string | Date;
748→      }>,
749→    ]>(
750→      [
751→        "SELECT id, orchestrator_status, task_id, error_message, started_at",
752→        "FROM agent_session",
753→        "WHERE orchestrator_status IN ['idle', 'error']",
754→        "AND workspace = $workspace",
755→        "ORDER BY started_at DESC",
756→        "LIMIT $limit;",
757→      ].join(" "),
758→      { workspace: input.workspaceRecord, limit: input.limit },
759→    )
760→    .collect<[
761→      Array<{
762→        id: RecordId<"agent_session", string>;
763→        orchestrator_status: string;
764→        task_id?: RecordId<"task", string>;
765→        error_message?: string;
766→        started_at: string | Date;
767→      }>,
768→    ]>();
769→
770→  const results: AgentAttentionSessionRow[] = [];
771→
772→  for (const row of rows) {
773→    let taskTitle: string | undefined;
774→    if (row.task_id) {
775→      const taskRow = await input.surreal.select<{ title: string }>(row.task_id);
776→      taskTitle = taskRow?.title;
777→    }
778→
779→    results.push({
780→      id: row.id,
781→      orchestrator_status: row.orchestrator_status as "idle" | "error",
782→      ...(row.task_id ? { task_id: row.task_id } : {}),
783→      ...(taskTitle ? { task_title: taskTitle } : {}),
784→      ...(row.error_message ? { error_message: row.error_message } : {}),
785→      started_at: row.started_at,
786→    });
787→  }
788→
789→  return results;
790→}
791→
792→export function mapAgentSessionToFeedItem(row: AgentAttentionSessionRow): GovernanceFeedItem {
793→  const rawId = row.id.id as string;
794→  const entityId = `agent_session:${rawId}`;
795→  const entityName = row.task_title ?? `Agent session ${rawId}`;
796→
797→  const isError = row.orchestrator_status === "error";
798→  const tier = isError ? "blocking" : "review";
799→
800→  const reason = isError
801→    ? `Agent error${row.error_message ? `: ${row.error_message}` : ""}`
802→    : `Agent completed work on '${entityName}' -- review ready`;
803→
804→  const actions: GovernanceFeedAction[] = isError
805→    ? [{ action: "discuss", label: "Discuss" }, { action: "abort", label: "Abort" }]
806→    : [{ action: "review", label: "Review" }, { action: "abort", label: "Abort" }];
807→
808→  return {
809→    id: `${entityId}:${row.orchestrator_status}`,
810→    tier,
811→    entityId,
812→    entityKind: "agent_session",
813→    entityName,
814→    reason,
815→    status: row.orchestrator_status,
816→    createdAt: row.started_at instanceof Date ? row.started_at.toISOString() : new Date(row.started_at).toISOString(),
817→    actions,
818→  };
819→}
