  1→import type { RecordId } from "surrealdb";
  2→import type {
  3→  EntityCategory,
  4→  EntityKind,
  5→  EntityPriority,
  6→  GovernanceFeedAction,
  7→  GovernanceFeedItem,
  8→  GovernanceFeedResponse,
  9→  ObservationSeverity,
 10→} from "../../shared/contracts";
 11→import { HttpError } from "../http/errors";
 12→import { elapsedMs, logError, logInfo, logWarn } from "../http/observability";
 13→import { jsonError, jsonResponse, toIsoString } from "../http/response";
 14→import { listWorkspaceOpenObservations } from "../observation/queries";
 15→import { listWorkspacePendingSuggestions } from "../suggestion/queries";
 16→import type { ServerDependencies } from "../runtime/types";
 17→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 18→import {
 19→  listAgentAttentionSessions,
 20→  listBlockedTasks,
 21→  listBlockingQuestions,
 22→  listLowConfidenceDecisions,
 23→  listPendingVetoIntents,
 24→  listProvisionalDecisions,
 25→  listRecentExtractions,
 26→  listRecentlyCompletedItems,
 27→  listStaleTasks,
 28→  listWorkspaceConflicts,
 29→  mapAgentSessionToFeedItem,
 30→  mapPendingIntentToFeedItem,
 31→} from "./feed-queries";
 32→
 33→const LOW_CONFIDENCE_THRESHOLD = 0.7;
 34→const STALE_DAYS = 7;
 35→const RECENT_COMPLETED_DAYS = 3;
 36→const AWARENESS_RECENCY_DAYS = 3;
 37→const FEED_ITEM_LIMIT = 20;
 38→
 39→export function createFeedRouteHandler(
 40→  deps: ServerDependencies,
 41→): (workspaceId: string) => Promise<Response> {
 42→  return (workspaceId: string) => handleFeed(deps, workspaceId);
 43→}
 44→
 45→async function handleFeed(deps: ServerDependencies, workspaceId: string): Promise<Response> {
 46→  const startedAt = performance.now();
 47→  logInfo("feed.started", "Governance feed request started", { workspaceId });
 48→
 49→  let workspaceRecord: RecordId<"workspace", string>;
 50→  try {
 51→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 52→  } catch (error) {
 53→    if (error instanceof HttpError) {
 54→      logWarn("feed.workspace_resolve.http_error", "Feed workspace resolve failed", {
 55→        workspaceId,
 56→        statusCode: error.status,
 57→      });
 58→      return jsonError(error.message, error.status);
 59→    }
 60→    logError("feed.workspace_resolve.failed", "Feed workspace resolve failed", error, { workspaceId });
 61→    return jsonError("failed to resolve workspace", 500);
 62→  }
 63→
 64→  try {
 65→    const queryInput = { surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT };
 66→
 67→    const [
 68→      provisionalDecisions,
 69→      conflicts,
 70→      blockingQuestions,
 71→      lowConfidenceDecisions,
 72→      blockedTasks,
 73→      observations,
 74→      suggestions,
 75→      staleTasks,
 76→      recentlyCompleted,
 77→      recentExtractions,
 78→      agentAttentionSessions,
 79→      pendingVetoIntents,
 80→    ] = await Promise.all([
 81→      listProvisionalDecisions(queryInput),
 82→      listWorkspaceConflicts(queryInput),
 83→      listBlockingQuestions(queryInput),
 84→      listLowConfidenceDecisions({ ...queryInput, confidenceThreshold: LOW_CONFIDENCE_THRESHOLD }),
 85→      listBlockedTasks(queryInput),
 86→      listWorkspaceOpenObservations({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 87→      listWorkspacePendingSuggestions({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 88→      listStaleTasks({ ...queryInput, staleDays: STALE_DAYS }),
 89→      listRecentlyCompletedItems({ ...queryInput, recentDays: RECENT_COMPLETED_DAYS }),
 90→      listRecentExtractions({ ...queryInput, cutoff: new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000) }),
 91→      listAgentAttentionSessions(queryInput),
 92→      listPendingVetoIntents(queryInput),
 93→    ]);
 94→
 95→    const blocking: GovernanceFeedItem[] = [];
 96→    const review: GovernanceFeedItem[] = [];
 97→    const awareness: GovernanceFeedItem[] = [];
 98→
 99→    // Blocking: provisional decisions
100→    for (const row of provisionalDecisions) {
101→      const rawId = row.id.id as string;
102→      blocking.push({
103→        id: `decision:${rawId}:${row.status}`,
104→        tier: "blocking",
105→        entityId: `decision:${rawId}`,
106→        entityKind: "decision",
107→        entityName: row.summary,
108→        reason: `${capitalize(row.status)} decision awaiting confirmation`,
109→        status: row.status,
110→        ...(row.project ? { project: row.project } : {}),
111→        ...(row.category ? { category: row.category as EntityCategory } : {}),
112→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
113→        createdAt: toIsoString(row.created_at),
114→        actions: decisionActions(),
115→      });
116→    }
117→
118→    // Blocking: conflicts
119→    for (const row of conflicts) {
120→      blocking.push({
121→        id: `conflict:${row.edgeId}`,
122→        tier: "blocking",
123→        entityId: `${row.fromKind}:${row.fromRecord.id as string}`,
124→        entityKind: row.fromKind as EntityKind,
125→        entityName: row.fromName,
126→        reason: row.description ?? `Conflicts with ${row.toName}`,
127→        status: "conflict",
128→        ...(row.severity ? { severity: row.severity as ObservationSeverity } : {}),
129→        createdAt: row.detectedAt,
130→        actions: conflictActions(),
131→        conflictTarget: {
132→          entityId: `${row.toKind}:${row.toRecord.id as string}`,
133→          entityKind: row.toKind as EntityKind,
134→          entityName: row.toName,
135→        },
136→      });
137→    }
138→
139→    // Blocking: high/critical questions
140→    for (const row of blockingQuestions) {
141→      const rawId = row.id.id as string;
142→      blocking.push({
143→        id: `question:${rawId}:blocking`,
144→        tier: "blocking",
145→        entityId: `question:${rawId}`,
146→        entityKind: "question",
147→        entityName: row.text,
148→        reason: `${capitalize(row.priority)} priority open question`,
149→        status: row.status,
150→        ...(row.project ? { project: row.project } : {}),
151→        ...(row.category ? { category: row.category as EntityCategory } : {}),
152→        priority: row.priority as EntityPriority,
153→        createdAt: toIsoString(row.created_at),
154→        actions: questionActions(),
155→      });
156→    }
157→
158→    // Blocking + Review: agent attention sessions (error -> blocking, idle -> review)
159→    for (const session of agentAttentionSessions) {
160→      const item = mapAgentSessionToFeedItem(session);
161→      if (item.tier === "blocking") {
162→        blocking.push(item);
163→      } else {
164→        review.push(item);
165→      }
166→    }
167→
168→    // Blocking: pending veto intents (agent actions awaiting human review)
169→    for (const intent of pendingVetoIntents) {
170→      blocking.push(mapPendingIntentToFeedItem(intent));
171→    }
172→
173→    // Review: low confidence decisions
174→    for (const row of lowConfidenceDecisions) {
175→      const rawId = row.id.id as string;
176→      review.push({
177→        id: `decision:${rawId}:low_confidence`,
178→        tier: "review",
179→        entityId: `decision:${rawId}`,
180→        entityKind: "decision",
181→        entityName: row.summary,
182→        reason: `Low confidence inferred decision (${Math.round(row.extraction_confidence * 100)}%)`,
183→        status: row.status,
184→        ...(row.project ? { project: row.project } : {}),
185→        ...(row.category ? { category: row.category as EntityCategory } : {}),
186→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
187→        createdAt: toIsoString(row.created_at),
188→        actions: decisionActions(),
189→      });
190→    }
191→
192→    // Review: blocked tasks
193→    for (const row of blockedTasks) {
194→      const rawId = row.id.id as string;
195→      review.push({
196→        id: `task:${rawId}:blocked`,
197→        tier: "review",
198→        entityId: `task:${rawId}`,
199→        entityKind: "task",
200→        entityName: row.title,
201→        reason: "Task is blocked",
202→        status: row.status,
203→        ...(row.project ? { project: row.project } : {}),
204→        ...(row.category ? { category: row.category as EntityCategory } : {}),
205→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
206→        createdAt: toIsoString(row.created_at),
207→        actions: blockedTaskActions(),
208→      });
209→    }
210→
211→    // Review: all open/acknowledged observations need human action
212→    for (const obs of observations) {
213→      review.push({
214→        id: `observation:${obs.id}:${obs.severity}`,
215→        tier: "review",
216→        entityId: `observation:${obs.id}`,
217→        entityKind: "observation",
218→        entityName: obs.text,
219→        reason: `${capitalize(obs.severity)} observation from ${obs.sourceAgent}`,
220→        status: obs.status,
221→        ...(obs.category ? { category: obs.category } : {}),
222→        severity: obs.severity,
223→        createdAt: obs.createdAt,
224→        actions: observationActions(obs.status),
225→      });
226→    }
227→
228→    // Review: pending suggestions from agents
229→    for (const sug of suggestions) {
230→      review.push({
231→        id: `suggestion:${sug.id}:${sug.category}`,
232→        tier: "review",
233→        entityId: `suggestion:${sug.id}`,
234→        entityKind: "suggestion",
235→        entityName: sug.text,
236→        reason: `${capitalize(sug.category)} suggestion from ${sug.suggestedBy} (confidence ${Math.round(sug.confidence * 100)}%)`,
237→        status: sug.status,
238→        createdAt: sug.createdAt,
239→        actions: suggestionActions(),
240→      });
241→    }
242→
243→    // Awareness items are filtered to the last AWARENESS_RECENCY_DAYS
244→    const awarenessCutoff = new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000);
245→
246→    // Awareness: stale tasks (only if they crossed the stale threshold recently)
247→    for (const row of staleTasks) {
248→      const ts = row.updated_at ? new Date(row.updated_at) : new Date(row.created_at);
249→      if (ts < awarenessCutoff) continue;
250→      const rawId = row.id.id as string;
251→      awareness.push({
252→        id: `task:${rawId}:stale`,
253→        tier: "awareness",
254→        entityId: `task:${rawId}`,
255→        entityKind: "task",
256→        entityName: row.title,
257→        reason: `Task open for over ${STALE_DAYS} days`,
258→        status: row.status,
259→        ...(row.project ? { project: row.project } : {}),
260→        ...(row.category ? { category: row.category as EntityCategory } : {}),
261→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
262→        createdAt: toIsoString(row.created_at),
263→        actions: staleTaskActions(),
264→      });
265→    }
266→
267→    // Awareness: recently completed (already filtered by RECENT_COMPLETED_DAYS query)
268→    for (const row of recentlyCompleted) {
269→      const rawId = row.id.id as string;
270→      awareness.push({
271→        id: `${row.kind}:${rawId}:completed`,
272→        tier: "awareness",
273→        entityId: `${row.kind}:${rawId}`,
274→        entityKind: row.kind as EntityKind,
275→        entityName: row.name,
276→        reason: `Recently completed ${row.kind}`,
277→        status: row.status,
278→        ...(row.project ? { project: row.project } : {}),
279→        ...(row.category ? { category: row.category as EntityCategory } : {}),
280→        createdAt: toIsoString(row.updated_at),
281→        actions: [],
282→      });
283→    }
284→
285→    // Awareness: recent extractions (skip entities already in higher tiers)
286→    const seenEntityIds = new Set<string>();
287→    for (const item of [...blocking, ...review, ...awareness]) {
288→      seenEntityIds.add(item.entityId);
289→    }
290→    for (const row of recentExtractions) {
291→      const entityId = `${row.entityKind}:${row.entityId}`;
292→      if (seenEntityIds.has(entityId)) continue;
293→      awareness.push({
294→        id: `extraction:${row.edgeId}`,
295→        tier: "awareness",
296→        entityId,
297→        entityKind: row.entityKind as EntityKind,
298→        entityName: row.entityName,
299→        reason: `Extracted from ${row.sourceKind.replace("_", " ")}`,
300→        status: "extracted",
301→        createdAt: row.extractedAt,
302→        actions: row.entityKind === "question" ? questionActions() : [],
303→      });
304→    }
305→
306→    const payload: GovernanceFeedResponse = {
307→      blocking,
308→      review,
309→      awareness,
310→      updatedAt: new Date().toISOString(),
311→    };
312→
313→    logInfo("feed.completed", "Governance feed request completed", {
314→      workspaceId,
315→      blockingCount: blocking.length,
316→      reviewCount: review.length,
317→      awarenessCount: awareness.length,
318→      durationMs: elapsedMs(startedAt),
319→    });
320→
321→    return jsonResponse(payload, 200);
322→  } catch (error) {
323→    logError("feed.failed", "Governance feed request failed", error, { workspaceId });
324→    const message = error instanceof Error ? error.message : "feed request failed";
325→    return jsonError(message, 500);
326→  }
327→}
